  ns: ['translations'],
  defaultNS: 'translations',

  resources: { en: { translations: {} } },
});

const HTMLCanvasElementMock = vi.fn(() => {
  return { prototype: { getContext: vi.fn() } };
});

const mockGlobal = () => {
  // mock user cookie
  Object.defineProperty(window.document, 'cookie', {
    value: `userId=1`,
    writable: true,
  });

  Object.defineProperty(window, 'matchMedia', {
    value: vi.fn().mockImplementation((query) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(), // deprecated
      removeListener: vi.fn(), // deprecated
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
    writable: true,
  });

  // This fixes undefined warnings testing @uiw/react-codemirror
  Object.defineProperty(window.document, 'createRange', {
    value: () => {
      const range = new Range();

      range.getBoundingClientRect = vi.fn();

      range.getClientRects = vi.fn(() => ({
        item: () => null,
        length: 0,
        [Symbol.iterator]: vi.fn(),
      }));

      range.setStart = vi.fn();
      range.setEnd = vi.fn();

      return range;
    },
    writable: true,
  });

  vi.stubGlobal('HTMLCanvasElement', HTMLCanvasElementMock);
};

beforeAll(() => {
  // only mock globals if it's a browser-like DOM
  // (we don't want globals for `node` environments)
  if (canUseDOM()) {
    mockGlobal();

    // Establish API mocking before all tests.
    server.listen({
